('pato_assado_na_brasa_bissau_guinean', 'Pato Assado na Brasa', 318, 24.6, 0.0, 24.4, 0.0, 0.0, 200, NULL, 'research', ARRAY['pato assado na brasa', 'charcoal duck'], 'poultry', NULL, 1, 'GW', 'Charcoal-roasted whole duck; a festive preparation requiring long, slow roasting over charcoal embers; duck fat bastes the skin creating a crispy exterior.', TRUE),
('camarao_refogado_com_palmito_bissau_guinean', 'Camarao Refogado com Palmito', 158, 18.4, 6.8, 6.4, 1.8, 1.2, 200, NULL, 'research', ARRAY['camarao refogado com palmito', 'shrimp palm heart sauté', 'camarao com palmito'], 'seafood', NULL, 1, 'GW', 'Shrimp sautéed with hearts of palm and palm oil; hearts of palm extracted from young oil palms are eaten as a vegetable and combined with shrimp in coastal stews.', TRUE),
('galinha_pelada_com_amendoim_bissau_guinean', 'Galinha Pelada com Amendoim', 278, 26.4, 7.8, 16.4, 2.0, 1.8, 250, NULL, 'research', ARRAY['galinha pelada com amendoim', 'skinless peanut chicken', 'frango sem pele com mancarra'], 'poultry', NULL, 1, 'GW', 'Skinless chicken in groundnut sauce; a lighter version of mancarra for health-conscious urban eaters, where removing the skin reduces fat while maintaining the peanut flavor.', TRUE),
('carne_de_porco_salgada_e_seca_bissau_guinean', 'Carne de Porco Salgada e Seca', 298, 32.4, 0.0, 18.8, 0.0, 0.0, 80, NULL, 'research', ARRAY['carne de porco salgada e seca', 'salt dried pork', 'porco salgado e seco'], 'meat', NULL, 1, 'GW', 'Salt-cured and dried pork; a Portuguese-derived preservation technique using heavy salt and air-drying; produced in non-Muslim coastal communities for long-term storage.', TRUE),
('peixe_com_ervas_frescas_bissau_guinean', 'Peixe com Ervas Frescas', 162, 22.8, 3.2, 6.2, 1.0, 1.0, 200, NULL, 'research', ARRAY['peixe com ervas frescas', 'herb fish', 'peixe com ervas aromáticas'], 'seafood', NULL, 1, 'GW', 'Fish with fresh herbs including parsley, cilantro, and basil; fresh herb usage has increased in Guinean cooking as urban herb gardens became more common.', TRUE),
('frangos_de_churrasco_bissau_guinean', 'Frangos de Churrasco', 244, 28.8, 0.8, 13.8, 0.2, 0.4, 200, NULL, 'research', ARRAY['frangos de churrasco', 'churrasco chicken', 'frango de churrasco'], 'poultry', NULL, 1, 'GW', 'Barbecue chicken halves grilled over coals; a popular weekend food sold at churrascaria stalls in Bissau''s residential neighborhoods, especially in the evenings.', TRUE),
