('lagosta_com_arroz_bissau_guinean', 'Lagosta com Arroz', 338, 22.4, 42.8, 6.4, 1.0, 0.8, 400, NULL, 'research', ARRAY['lagosta com arroz', 'lobster rice', 'arroz de lagosta'], 'seafood', NULL, 1, 'GW', 'Lobster rice; a celebratory dish combining freshly caught spiny lobster with locally grown rice, representing Guinea-Bissau''s finest coastal cuisine.', TRUE),
('pombo_assado_bissau_guinean', 'Pombo Assado', 228, 28.4, 0.0, 12.4, 0.0, 0.0, 200, 400, 'research', ARRAY['pombo assado', 'roasted pigeon', 'pombo bravo assado'], 'poultry', NULL, 1, 'GW', 'Roasted pigeon; domestic and wild pigeons are raised or hunted throughout Guinea-Bissau and eaten as a special-occasion protein, particularly in rural households.', TRUE),
('carpa_frita_bissau_guinean', 'Carpa Frita', 188, 22.4, 5.2, 8.6, 0.4, 0.8, 180, NULL, 'research', ARRAY['carpa frita', 'fried carp'], 'seafood', NULL, 1, 'GW', 'Fried carp from freshwater ponds and rivers; carp aquaculture has been introduced in Guinea-Bissau by development organizations and supplies urban markets.', TRUE),
('frango_cozido_com_arroz_bissau_guinean', 'Frango Cozido com Arroz', 318, 24.8, 37.2, 7.4, 0.8, 0.4, 400, NULL, 'research', ARRAY['frango cozido com arroz', 'boiled chicken rice', 'frango cozido com arroz branco'], 'poultry', NULL, 1, 'GW', 'Boiled chicken with white rice; the simplest complete meal in Guinea-Bissau, valued for its gentle flavors and used as sick food and as a reference point for all other chicken dishes.', TRUE),
('sopa_de_feijao_com_carne_bissau_guinean', 'Sopa de Feijao com Carne', 252, 18.4, 24.8, 8.4, 6.4, 2.2, 400, NULL, 'research', ARRAY['sopa de feijao com carne', 'bean meat soup', 'sopa de feijão com carne'], 'soup', NULL, 1, 'GW', 'Bean and meat soup; black-eyed peas or cowpeas cooked with beef or goat is a complete protein meal eaten across all ethnic groups in Guinea-Bissau.', TRUE),
('barracuda_fumada_bissau_guinean', 'Barracuda Fumada', 224, 36.8, 0.0, 8.4, 0.0, 0.0, 80, NULL, 'research', ARRAY['barracuda fumada', 'smoked barracuda', 'barracuda defumada'], 'seafood', NULL, 1, 'GW', 'Smoked barracuda; barracuda''s firm, oily flesh makes it ideal for smoking and it is traded inland from coastal fishing communities to markets in Bafatá and Gabú.', TRUE),
