('ameijoas_ao_vapor_com_ervas_bissau_guinean', 'Ameijoas ao Vapor com Ervas', 68, 11.4, 3.2, 0.8, 0.0, 0.4, 150, 10, 'research', ARRAY['ameijoas ao vapor com ervas', 'steamed herb clams', 'ameijoas no vapor'], 'seafood', NULL, 1, 'GW', 'Steamed clams with fresh herbs; clams from Guinea-Bissau''s estuary muds are steamed with garlic and local herbs in a rapid preparation that preserves their brininess.', TRUE),
('cabrito_com_arroz_pilaf_bissau_guinean', 'Cabrito com Arroz Pilaf', 352, 26.4, 38.8, 11.4, 1.2, 0.8, 400, NULL, 'research', ARRAY['cabrito com arroz pilaf', 'goat rice pilaf', 'cabrito com arroz'], 'meat', NULL, 1, 'GW', 'Goat with pilaf rice; this combination of spiced goat with rice shows Fula and Mandinka Sahel culinary influence, where rice and meat are cooked together in a single pot.', TRUE),
