('palm_nut_sauce_bissau_guinean', 'Palm Nut Sauce', 210, 2.8, 6.5, 19.5, 2.1, 1.5, 120, NULL, 'research', ARRAY['palm nut sauce', 'molho de palma', 'palm cream sauce'], 'traditional', NULL, 1, 'GW', 'Rich sauce made from boiled and pressed palm nuts (Elaeis guineensis), used as a base for stews and to dress rice. Central to Guinean cooking identity.', TRUE),
