('folhas_de_batata_doce_cozidas_bissau_guinean', 'Folhas de Batata-Doce Cozidas', 42, 2.8, 6.5, 0.8, 2.5, 1.8, 150, NULL, 'research', ARRAY['folhas de batata-doce cozidas', 'sweet potato greens', 'folhas de batata'], 'vegetables', NULL, 1, 'GW', 'Boiled sweet potato leaves seasoned with palm oil and salt. A nutritious and inexpensive green vegetable consumed widely in rural areas.', TRUE),
('acelga_guisada_bissau_guinean', 'Acelga Guisada', 35, 1.8, 4.5, 1.2, 1.8, 1.5, 160, NULL, 'research', ARRAY['acelga guisada', 'sautéed chard', 'chard stew'], 'vegetables', NULL, 1, 'GW', 'Swiss chard sautéed with onions and tomatoes in palm or groundnut oil. A Portuguese-influenced preparation adapted to local tastes.', TRUE),
