('feijao_verde_cozido_bissau_guinean', 'Feijão Verde Cozido', 38, 2.4, 6.8, 0.4, 2.8, 2.5, 150, NULL, 'research', ARRAY['feijão verde cozido', 'boiled green beans', 'vagem verde'], 'vegetables', NULL, 1, 'GW', 'Boiled green beans dressed with palm oil and garlic. Green beans are grown in the highlands and serve as a common side dish.', TRUE),
