('cuscuz_de_milho_bissau_guinean', 'Cuscuz de Milho', 175, 4.2, 36.5, 2.0, 3.2, 1.0, 150, NULL, 'research', ARRAY['cuscuz de milho', 'cornmeal couscous', 'couscous de milho'], 'side dishes', NULL, 1, 'GW', 'Steamed cornmeal couscous, a West African adaptation influenced by North African and Portuguese couscous traditions. Served with fish or vegetable stews.', TRUE),
