('salada_de_abacate_bissau_guinean', 'Salada de Abacate', 112, 1.5, 5.8, 9.8, 4.5, 0.5, 130, NULL, 'research', ARRAY['salada de abacate', 'avocado salad', 'salada de abacateiro'], 'salads', NULL, 1, 'GW', 'Sliced avocado with lemon juice and salt, sometimes mixed with tomato. Avocado trees are common in home gardens throughout Guinea-Bissau.', TRUE),
('ovos_cozidos_bissau_guinean', 'Ovos Cozidos', 155, 12.5, 1.1, 10.6, 0.0, 1.1, 100, 50, 'research', ARRAY['ovos cozidos', 'hard boiled eggs', 'ovos duros'], 'egg dishes', NULL, 1, 'GW', 'Hard-boiled eggs, a simple protein source eaten as a side dish or snack. Eggs from free-range chickens are common in rural households.', TRUE),
