('ovos_mexidos_com_tomate_bissau_guinean', 'Ovos Mexidos com Tomate', 150, 11.2, 4.8, 10.0, 0.8, 3.0, 120, NULL, 'research', ARRAY['ovos mexidos com tomate', 'scrambled eggs with tomato', 'ovos mexidos com tomates'], 'egg dishes', NULL, 1, 'GW', 'Scrambled eggs with tomatoes and onions, a common breakfast preparation merging Portuguese scrambled egg traditions with local tomato cultivation.', TRUE),
('quiabo_frito_bissau_guinean', 'Quiabo Frito', 85, 2.0, 9.5, 4.5, 4.0, 1.8, 120, NULL, 'research', ARRAY['quiabo frito', 'fried okra', 'quiabo salteado'], 'vegetables', NULL, 1, 'GW', 'Fried okra slices with onions and chili, a crispy side dish or street food snack. Okra originated in northeastern Africa and spread throughout West Africa.', TRUE),
('molho_de_quiabo_com_camarao_seco_bissau_guinean', 'Molho de Quiabo com Camarão Seco', 110, 8.5, 8.8, 4.8, 3.5, 2.0, 150, NULL, 'research', ARRAY['molho de quiabo com camarão seco', 'okra shrimp sauce', 'gumbo de camarão'], 'traditional', NULL, 1, 'GW', 'Okra sauce enriched with dried shrimp, a combination found across coastal Guinea-Bissau. Dried shrimp provide umami depth to the mucilaginous okra base.', TRUE),
('folhas_de_moringa_salteadas_bissau_guinean', 'Folhas de Moringa Salteadas', 62, 5.5, 6.8, 1.8, 3.5, 2.0, 130, NULL, 'research', ARRAY['folhas de moringa salteadas', 'sautéed moringa', 'moringa leaves sauté'], 'vegetables', NULL, 1, 'GW', 'Sautéed moringa leaves with garlic and palm oil. Moringa is called the ''miracle tree'' locally for its exceptional nutritional profile and drought tolerance.', TRUE),
('sopa_de_legumes_bissau_guinean', 'Sopa de Legumes', 55, 2.2, 9.5, 1.2, 2.8, 3.5, 250, NULL, 'research', ARRAY['sopa de legumes', 'mixed vegetable soup', 'caldo de legumes'], 'side dishes', NULL, 1, 'GW', 'Mixed vegetable soup with sweet potato, cassava, pumpkin, and greens. A Portuguese-influenced soup made with locally available vegetables.', TRUE),
