('mandioca_frita_bissau_guinean', 'Mandioca Frita', 225, 1.5, 42.0, 7.5, 2.0, 1.5, 120, NULL, 'research', ARRAY['mandioca frita', 'fried cassava', 'chips de mandioca'], 'side dishes', NULL, 1, 'GW', 'Deep-fried cassava chips or wedges, a popular street food and side dish. Sold by street vendors throughout Bissau''s markets.', TRUE),
('inhame_assado_bissau_guinean', 'Inhame Assado', 135, 1.8, 31.5, 0.5, 4.5, 0.5, 150, NULL, 'research', ARRAY['inhame assado', 'roasted yam', 'inhame nas brasas'], 'side dishes', NULL, 1, 'GW', 'Roasted yam cooked directly in embers or on a wood fire. Roasted yam is a traditional cooking method predating Portuguese contact.', TRUE),
('batata_doce_assada_bissau_guinean', 'Batata-Doce Assada', 105, 2.0, 24.5, 0.2, 3.8, 5.5, 150, NULL, 'research', ARRAY['batata-doce assada', 'roasted sweet potato', 'batata doce nas brasas'], 'side dishes', NULL, 1, 'GW', 'Roasted sweet potato, a beloved snack and side dish cooked in hot embers by street vendors. Natural sugars caramelize during roasting for a sweet flavor.', TRUE),
('abobora_refogada_bissau_guinean', 'Abóbora Refogada', 52, 1.2, 7.5, 1.8, 1.5, 3.5, 150, NULL, 'research', ARRAY['abóbora refogada', 'sautéed pumpkin', 'pumpkin stew'], 'vegetables', NULL, 1, 'GW', 'Sautéed pumpkin with onions, tomatoes, and spices. Pumpkin (abóbora) is widely cultivated in kitchen gardens and used in various preparations.', TRUE),
('berinjela_assada_bissau_guinean', 'Berinjela Assada', 38, 1.2, 6.5, 1.5, 3.0, 3.8, 130, NULL, 'research', ARRAY['berinjela assada', 'roasted eggplant', 'bringela assada'], 'vegetables', NULL, 1, 'GW', 'Roasted eggplant seasoned with palm oil and herbs. Eggplant arrived via Portuguese and Arab trade routes and became integrated into Guinean cooking.', TRUE),
('pimenta_recheada_bissau_guinean', 'Pimenta Recheada', 95, 4.5, 12.0, 3.5, 2.5, 5.0, 120, 60, 'research', ARRAY['pimenta recheada', 'stuffed peppers', 'pimentos recheados'], 'vegetables', NULL, 1, 'GW', 'Stuffed peppers filled with rice and herbs, a Portuguese culinary influence adapted with local spices. Served as a side dish in special occasions.', TRUE),
('pure_de_mandioca_bissau_guinean', 'Puré de Mandioca', 148, 1.5, 33.8, 2.5, 2.0, 1.5, 180, NULL, 'research', ARRAY['puré de mandioca', 'mashed cassava', 'cassava mash'], 'side dishes', NULL, 1, 'GW', 'Mashed cassava with palm oil and salt, a comforting side dish eaten with soups and stews. The creamy texture makes it a popular accompaniment.', TRUE),
('folhas_de_amendoim_cozidas_bissau_guinean', 'Folhas de Amendoim Cozidas', 45, 3.8, 5.5, 1.0, 3.2, 1.2, 140, NULL, 'research', ARRAY['folhas de amendoim cozidas', 'peanut leaves', 'folhas de mancarra'], 'vegetables', NULL, 1, 'GW', 'Boiled peanut leaves, particularly common in rural areas where the entire peanut plant is utilized. Nutritious greens rarely documented outside West Africa.', TRUE),
('bredo_cozido_bissau_guinean', 'Bredo Cozido', 28, 2.5, 3.8, 0.5, 2.8, 0.5, 140, NULL, 'research', ARRAY['bredo cozido', 'amaranth leaves', 'amaranto cozido'], 'vegetables', NULL, 1, 'GW', 'Boiled amaranth leaves (Amaranthus species), a highly nutritious wild and cultivated green used throughout Guinea-Bissau. Rich in iron and calcium.', TRUE),
('cenoura_refogada_bissau_guinean', 'Cenoura Refogada', 48, 1.0, 9.2, 1.5, 2.5, 4.5, 130, NULL, 'research', ARRAY['cenoura refogada', 'sautéed carrots', 'cenouras salteadas'], 'vegetables', NULL, 1, 'GW', 'Sautéed carrots with garlic and herbs, introduced through Portuguese colonial influence. Carrots are grown in market gardens for urban consumption.', TRUE),
('repolho_refogado_bissau_guinean', 'Repolho Refogado', 38, 1.5, 5.8, 1.5, 2.0, 3.0, 140, NULL, 'research', ARRAY['repolho refogado', 'sautéed cabbage', 'couve-repolho refogada'], 'vegetables', NULL, 1, 'GW', 'Sautéed cabbage with onions and palm oil, a common side dish in both rural and urban settings. Cabbage cultivation was expanded during Portuguese colonialism.', TRUE),
('pao_de_centeio_bissau_guinean', 'Pão de Centeio', 245, 8.0, 48.0, 1.8, 6.5, 2.0, 60, 60, 'research', ARRAY['pão de centeio', 'rye bread', 'pão integral de centeio'], 'bread', NULL, 1, 'GW', 'Rye bread, a Portuguese bread variety found in Bissau''s bakeries catering to the urban middle class and expat community.', TRUE),
