('broa_de_fuba_bissau_guinean', 'Broa de Fubá', 255, 5.5, 50.5, 4.0, 3.5, 5.0, 70, 70, 'research', ARRAY['broa de fubá', 'cornmeal broa', 'pão de fubá'], 'bread', NULL, 1, 'GW', 'Cornmeal flatbread derived from Portuguese broa tradition, adapted with local fubá (maize flour). A dense, hearty bread popular in rural Guinea-Bissau.', TRUE),
('pastel_de_farinha_bissau_guinean', 'Pastel de Farinha', 280, 4.5, 38.5, 13.5, 1.5, 2.5, 60, 60, 'research', ARRAY['pastel de farinha', 'fried pastry', 'pastilha'], 'pastry', NULL, 1, 'GW', 'Deep-fried flour pastry similar to Portuguese pastel, filled with vegetables or fish. A common street food snack influenced by colonial baking traditions.', TRUE),
('queijada_de_coco_bissau_guinean', 'Queijada de Coco', 320, 5.5, 45.0, 14.0, 2.5, 28.0, 50, 50, 'research', ARRAY['queijada de coco', 'coconut tart', 'tarte de coco'], 'pastry', NULL, 1, 'GW', 'Coconut tart with Portuguese queijada origins, made with fresh coconut and eggs. A festive pastry served at celebrations in coastal areas.', TRUE),
('biscoito_de_amendoim_bissau_guinean', 'Biscoito de Amendoim', 485, 14.5, 48.0, 28.0, 4.0, 18.0, 30, 15, 'research', ARRAY['biscoito de amendoim', 'peanut biscuits', 'mancarra biscoito'], 'pastry', NULL, 1, 'GW', 'Peanut cookies made with ground peanuts (mancarra) and local palm sugar. A traditional confection that showcases the importance of peanuts in Guinean cuisine.', TRUE),
('leite_de_coco_fresco_bissau_guinean', 'Leite de Coco Fresco', 220, 2.3, 5.5, 22.5, 2.2, 3.5, 100, NULL, 'research', ARRAY['leite de coco fresco', 'fresh coconut milk', 'leite de coco natural'], 'dairy', NULL, 1, 'GW', 'Freshly extracted coconut milk from grated coconuts, used in cooking and consumed as a beverage in the Bijagos Islands. Not dairy in the strict sense but functions as a milk substitute.', TRUE),
