('salada_de_mandioca_cozida_bissau_guinean', 'Salada de Mandioca Cozida', 148, 1.5, 34.8, 2.5, 2.0, 1.8, 150, NULL, 'research', ARRAY['salada de mandioca cozida', 'cassava salad', 'salada de manioc'], 'salads', NULL, 1, 'GW', 'Cold boiled cassava slices dressed with palm oil, onions, and lemon juice. A simple but satisfying salad eaten throughout the country.', TRUE),
('salada_de_batata_doce_bissau_guinean', 'Salada de Batata-Doce', 92, 1.8, 20.5, 1.5, 3.2, 5.0, 150, NULL, 'research', ARRAY['salada de batata-doce', 'sweet potato salad', 'salada de batata doce'], 'salads', NULL, 1, 'GW', 'Boiled sweet potato salad dressed with vinegar and onions in Portuguese style. Sweet potato salads are popular as light side dishes.', TRUE),
