('salada_de_feijao_preto_bissau_guinean', 'Salada de Feijão Preto', 142, 8.8, 24.5, 1.2, 7.5, 1.0, 150, NULL, 'research', ARRAY['salada de feijão preto', 'black bean salad', 'salada de feijão negro'], 'salads', NULL, 1, 'GW', 'Black bean salad with onions, palm oil, and herbs. Black beans are less common than cowpeas but available in urban markets.', TRUE),
('ensopado_de_legumes_bissau_guinean', 'Ensopado de Legumes', 78, 2.5, 14.5, 2.0, 3.5, 4.5, 200, NULL, 'research', ARRAY['ensopado de legumes', 'vegetable stew', 'guisado de legumes'], 'side dishes', NULL, 1, 'GW', 'Portuguese-style vegetable stew with multiple local vegetables slow-cooked together. The ensopado technique was introduced during colonial rule.', TRUE),
('feijao_guisado_bissau_guinean', 'Feijão Guisado', 120, 6.5, 19.5, 2.8, 6.0, 1.0, 180, NULL, 'research', ARRAY['feijão guisado', 'stewed beans', 'feijão cozido com molho'], 'side dishes', NULL, 1, 'GW', 'Stewed beans with onions, tomatoes, and palm oil. Beans (feijão) of various types are central protein sources in Guinean diet.', TRUE),
('arroz_de_tomate_bissau_guinean', 'Arroz de Tomate', 155, 3.2, 30.5, 2.8, 0.8, 2.5, 180, NULL, 'research', ARRAY['arroz de tomate', 'tomato rice', 'arroz encarnado'], 'side dishes', NULL, 1, 'GW', 'Rice cooked with tomato sauce, a Portuguese-influenced preparation common in urban Guinea-Bissau. Often colored red with tomato paste.', TRUE),
('pirao_de_milho_bissau_guinean', 'Pirão de Milho', 158, 3.5, 33.5, 2.0, 2.8, 1.0, 180, NULL, 'research', ARRAY['pirão de milho', 'maize porridge', 'ugali guinéense'], 'side dishes', NULL, 1, 'GW', 'Maize porridge cooked thick and eaten as a starchy staple. Corn pirão is common in areas where maize is the primary cereal crop.', TRUE),
('banana_assada_bissau_guinean', 'Banana Assada', 122, 1.5, 28.5, 0.5, 3.5, 18.0, 120, 120, 'research', ARRAY['banana assada', 'roasted plantain', 'banana no forno'], 'side dishes', NULL, 1, 'GW', 'Roasted plantain or sweet banana cooked on embers, a street food and side dish. Plantains are among the most widely consumed foods in Guinea-Bissau.', TRUE),
