('benachin_de_legumes_bissau_guinean', 'Benachin de Legumes', 165, 4.5, 32.0, 3.5, 3.5, 3.0, 250, NULL, 'research', ARRAY['benachin de legumes', 'vegetable jollof rice', 'thiéboudienne légumes', 'benachin vegetal'], 'traditional', NULL, 1, 'GW', 'One-pot vegetable rice dish, the Guinean adaptation of Senegalese thiéboudienne without fish. Vegetables like eggplant, cassava, and cabbage are cooked with rice.', TRUE),
