('pao_de_lo_bissau_guinean', 'Pão de Ló', 295, 8.5, 52.5, 6.5, 0.5, 30.0, 70, 70, 'research', ARRAY['pão de ló', 'portuguese sponge cake', 'génoise guinéense'], 'pastry', NULL, 1, 'GW', 'Portuguese sponge cake introduced during colonial rule, baked for baptisms and weddings. The pão de ló is a festive cake now made by Bissau''s bakers.', TRUE),
('bolo_de_milho_bissau_guinean', 'Bolo de Milho', 265, 5.8, 48.5, 6.5, 2.8, 15.0, 80, 80, 'research', ARRAY['bolo de milho', 'cornmeal cake', 'bolo de fubá'], 'pastry', NULL, 1, 'GW', 'Cornmeal cake sweetened with local sugar, combining Portuguese cake-baking techniques with local maize flour. A common celebration cake in rural areas.', TRUE),
