('pasta_de_amendoim_bissau_guinean', 'Pasta de Amendoim', 590, 24.0, 20.5, 50.0, 6.5, 8.5, 30, NULL, 'research', ARRAY['pasta de amendoim', 'peanut paste', 'pate de mancarra'], 'side dishes', NULL, 1, 'GW', 'Homemade peanut paste ground from roasted peanuts, spread on bread or used in cooking. The traditional peanut paste predates commercial peanut butter.', TRUE),
