('folhas_de_malabar_cozidas_bissau_guinean', 'Folhas de Malabar Cozidas', 40, 3.2, 5.8, 0.6, 3.8, 0.8, 140, NULL, 'research', ARRAY['folhas de malabar cozidas', 'malabar spinach', 'espinafre de trepadeira'], 'vegetables', NULL, 1, 'GW', 'Malabar spinach (Basella alba) leaves boiled and dressed with oil. A heat-tolerant tropical green that grows abundantly in Guinea-Bissau''s climate.', TRUE),
('folhas_de_cenoura_cozidas_bissau_guinean', 'Folhas de Cenoura Cozidas', 28, 2.8, 3.5, 0.5, 3.0, 0.8, 120, NULL, 'research', ARRAY['folhas de cenoura cozidas', 'carrot tops', 'rama de cenoura'], 'vegetables', NULL, 1, 'GW', 'Carrot tops cooked as a green vegetable, utilizing the entire carrot plant. The practice of cooking carrot greens reflects the no-waste ethos of Guinean rural cooking.', TRUE),
