('farinha_de_mandioca_torrada_bissau_guinean', 'Farinha de Mandioca Torrada', 360, 2.5, 82.5, 0.8, 4.5, 2.0, 50, NULL, 'research', ARRAY['farinha de mandioca torrada', 'toasted cassava flour', 'gari', 'farinha grossa'], 'side dishes', NULL, 1, 'GW', 'Toasted cassava flour (gari-style) eaten as a dry accompaniment to soups and sauces. The coarse-textured flour is sprinkled over food to absorb liquid.', TRUE),
