('malagueta_em_conserva_bissau_guinean', 'Malagueta em Conserva', 28, 1.2, 5.5, 0.5, 2.5, 3.0, 20, NULL, 'research', ARRAY['malagueta em conserva', 'pickled chili', 'piri-piri conservado'], 'side dishes', NULL, 1, 'GW', 'Preserved chili peppers in vinegar or brine, a Portuguese preservation technique applied to local hot pepper varieties. Served as a condiment with all meals.', TRUE),
('caldo_de_batata_doce_bissau_guinean', 'Caldo de Batata-Doce', 72, 1.5, 16.5, 0.8, 2.5, 5.5, 250, NULL, 'research', ARRAY['caldo de batata-doce', 'sweet potato soup', 'sopa de batata doce'], 'side dishes', NULL, 1, 'GW', 'Sweet potato broth soup, a light and comforting preparation used as a first course. Sweet potato broth provides natural sweetness and nutrition.', TRUE),
('azeitonas_temperadas_bissau_guinean', 'Azeitonas Temperadas', 148, 1.0, 4.0, 14.5, 3.5, 0.5, 40, NULL, 'research', ARRAY['azeitonas temperadas', 'seasoned olives', 'azeitonas marinadas'], 'side dishes', NULL, 1, 'GW', 'Seasoned olives imported from Portugal and consumed as an appetizer in urban restaurants. A direct Portuguese cultural import found in Bissau''s formal dining.', TRUE),
('bacalhau_com_grao_bissau_guinean', 'Bacalhau com Grão', 188, 20.5, 16.5, 5.5, 5.0, 1.5, 200, NULL, 'research', ARRAY['bacalhau com grão', 'salt cod with chickpeas', 'bacalhau com grão-de-bico'], 'traditional', NULL, 1, 'GW', 'Salt cod with chickpeas, a classic Portuguese dish maintained in Guinea-Bissau. Despite being landlocked from Atlantic cod, this dish persists due to colonial food culture.', TRUE),
('canjica_de_milho_bissau_guinean', 'Canjica de Milho', 145, 3.5, 30.5, 2.0, 2.5, 8.5, 200, NULL, 'research', ARRAY['canjica de milho', 'sweet corn porridge', 'canjica doce'], 'traditional', NULL, 1, 'GW', 'Sweet hominy corn porridge cooked with coconut milk and sugar, eaten as a dessert or breakfast. Brought from Brazilian food exchanges through the African diaspora.', TRUE),
('feijao_vermelho_guisado_bissau_guinean', 'Feijão Vermelho Guisado', 132, 7.8, 22.5, 1.8, 6.8, 1.5, 180, NULL, 'research', ARRAY['feijão vermelho guisado', 'red kidney bean stew', 'feijão encarnado guisado'], 'side dishes', NULL, 1, 'GW', 'Stewed red kidney beans with onions, tomatoes, and spices. Red kidney beans are a popular protein source in urban Guinea-Bissau.', TRUE),
('folhas_de_rabano_cozidas_bissau_guinean', 'Folhas de Rábano Cozidas', 22, 1.8, 3.5, 0.2, 2.5, 1.5, 120, NULL, 'research', ARRAY['folhas de rábano cozidas', 'radish greens', 'folhas de rabanete cozidas'], 'vegetables', NULL, 1, 'GW', 'Boiled radish leaves, a zero-waste vegetable preparation using the often-discarded greens. Radish tops are nutritious and have a mild peppery flavor.', TRUE),
('salada_de_grao_cozido_bissau_guinean', 'Salada de Grão Cozido', 168, 8.8, 27.5, 3.0, 7.5, 4.5, 150, NULL, 'research', ARRAY['salada de grão cozido', 'chickpea salad', 'salada de grão-de-bico'], 'salads', NULL, 1, 'GW', 'Chickpea salad with onions, parsley, and lemon dressing, reflecting Portuguese culinary influence. A nutritious and filling salad for urban diners.', TRUE),
('papaia_verde_em_salada_bissau_guinean', 'Papaia Verde em Salada', 28, 0.8, 6.0, 0.2, 1.8, 2.5, 120, NULL, 'research', ARRAY['papaia verde em salada', 'green papaya salad', 'salada de papaia verde'], 'salads', NULL, 1, 'GW', 'Shredded unripe papaya salad with chili and lime juice, similar to Southeast Asian som tum but adapted to West African flavors. Papaya grows abundantly throughout Guinea-Bissau.', TRUE),
('manga_verde_em_salada_bissau_guinean', 'Manga Verde em Salada', 38, 0.8, 8.5, 0.2, 2.0, 5.5, 120, NULL, 'research', ARRAY['manga verde em salada', 'green mango salad', 'manga verde temperada'], 'salads', NULL, 1, 'GW', 'Sliced unripe mango with chili, salt, and lime, a tart and refreshing snack salad. Mango trees are found throughout the country and unripe fruit is widely consumed.', TRUE),
('salada_de_beringela_assada_bissau_guinean', 'Salada de Beringela Assada', 55, 1.5, 7.5, 2.8, 3.5, 4.0, 130, NULL, 'research', ARRAY['salada de beringela assada', 'roasted eggplant salad', 'zaalouk de beringela'], 'salads', NULL, 1, 'GW', 'Roasted eggplant salad mashed with garlic and olive oil, resembling baba ganoush, a Portuguese zaalouk-inspired preparation found in urban Bissau.', TRUE),
('tapioca_frita_bissau_guinean', 'Tapioca Frita', 195, 0.5, 44.0, 3.5, 0.8, 2.0, 80, 80, 'research', ARRAY['tapioca frita', 'tapioca crepe', 'tapioca assada'], 'pastry', NULL, 1, 'GW', 'Fried tapioca crepe made from hydrated cassava starch, eaten as a quick breakfast or snack. The tapioca preparation was influenced by Brazilian cassava traditions.', TRUE),
('pao_integral_bissau_guinean', 'Pão Integral', 252, 9.5, 47.5, 2.8, 6.5, 2.5, 70, 70, 'research', ARRAY['pão integral', 'whole wheat bread', 'pão de farinha integral'], 'bread', NULL, 1, 'GW', 'Whole wheat bread introduced in urban bakeries catering to health-conscious consumers. The wholemeal bread reflects growing urban middle-class food preferences.', TRUE),
('pao_de_batata_doce_bissau_guinean', 'Pão de Batata-Doce', 248, 6.8, 49.5, 2.5, 2.8, 8.5, 70, 70, 'research', ARRAY['pão de batata-doce', 'sweet potato loaf', 'pão de batata doce'], 'bread', NULL, 1, 'GW', 'Sweet potato bread made with mashed sweet potato incorporated into the dough, giving a moist, slightly sweet loaf. A creative fusion of Portuguese bread-making and local ingredients.', TRUE),
('biscoitos_de_mandioca_bissau_guinean', 'Biscoitos de Mandioca', 368, 2.5, 78.0, 5.5, 2.5, 8.0, 40, 20, 'research', ARRAY['biscoitos de mandioca', 'cassava crackers', 'beiju'], 'pastry', NULL, 1, 'GW', 'Crispy cassava biscuits made from cassava starch and coconut, a gluten-free snack sold in markets. A traditional confection that predates wheat bread introduction.', TRUE),
('doce_de_caju_bissau_guinean', 'Doce de Caju', 215, 1.5, 52.5, 0.5, 1.5, 50.0, 40, NULL, 'research', ARRAY['doce de caju', 'cashew jam', 'geleia de caju'], 'pastry', NULL, 1, 'GW', 'Cashew fruit jam made by cooking cashew apple pulp with sugar. Guinea-Bissau is a major cashew producer and the fruit (not just the nut) is used extensively.', TRUE),
('abacaxi_grelhado_bissau_guinean', 'Abacaxi Grelhado', 65, 0.5, 15.5, 0.2, 1.5, 13.5, 120, NULL, 'research', ARRAY['abacaxi grelhado', 'grilled pineapple', 'ananás grelhado'], 'side dishes', NULL, 1, 'GW', 'Grilled pineapple slices served as a side dish or dessert, caramelized on a wood-fired grill. Pineapple is cultivated locally and the grilled preparation is popular at gatherings.', TRUE),
('folhas_de_figueira_cozidas_bissau_guinean', 'Folhas de Figueira Cozidas', 38, 3.0, 5.8, 0.5, 4.2, 1.0, 130, NULL, 'research', ARRAY['folhas de figueira cozidas', 'fig leaves', 'folhas de figo cozidas'], 'vegetables', NULL, 1, 'GW', 'Boiled young fig tree leaves, eaten as a vegetable in food-scarce periods. The leaves require extended cooking to soften their tough texture.', TRUE),
('molho_de_berinjela_bissau_guinean', 'Molho de Berinjela', 62, 1.5, 9.0, 3.0, 3.5, 5.5, 150, NULL, 'research', ARRAY['molho de berinjela', 'eggplant sauce', 'molho de beringela'], 'traditional', NULL, 1, 'GW', 'Eggplant sauce cooked with palm oil, tomatoes, and peppers. Used as a side sauce to accompany grilled fish or pounded yam.', TRUE),
('arroz_frito_com_ovos_bissau_guinean', 'Arroz Frito com Ovos', 210, 7.5, 32.5, 7.0, 0.8, 1.0, 200, NULL, 'research', ARRAY['arroz frito com ovos', 'egg fried rice', 'arroz frito'], 'side dishes', NULL, 1, 'GW', 'Fried rice with eggs and vegetables, a practical dish using leftover rice. The egg-fried rice technique shows Asian and Portuguese cooking cross-influences.', TRUE),
('esparregado_bissau_guinean', 'Esparregado', 58, 3.5, 5.5, 3.0, 2.8, 1.5, 150, NULL, 'research', ARRAY['esparregado', 'creamed spinach', 'espinafre amassado'], 'vegetables', NULL, 1, 'GW', 'Portuguese-style creamed spinach or greens made by pureeing cooked spinach with olive oil and garlic. A directly transferred Portuguese side dish found in Bissau restaurants.', TRUE),
('caldo_de_inhame_bissau_guinean', 'Caldo de Inhame', 98, 2.0, 22.5, 1.5, 3.5, 1.0, 250, NULL, 'research', ARRAY['caldo de inhame', 'yam soup', 'sopa de inhame'], 'side dishes', NULL, 1, 'GW', 'Yam broth soup with herbs and spices, a traditional preparation used as a restorative food. Yam broth is given to recovering patients in traditional medicine.', TRUE),
('quiabo_seco_bissau_guinean', 'Quiabo Seco', 285, 15.5, 50.5, 2.5, 20.0, 5.5, 30, NULL, 'research', ARRAY['quiabo seco', 'dried okra', 'quiabo em pó'], 'traditional', NULL, 1, 'GW', 'Sun-dried okra pods, ground into powder for preservation. Dried okra powder is used to thicken soups and sauces during the dry season when fresh okra is unavailable.', TRUE),
('noz_de_cola_bissau_guinean', 'Noz de Cola', 165, 2.5, 38.5, 0.5, 2.5, 3.0, 30, 10, 'research', ARRAY['noz de cola', 'kola nut', 'cola'], 'traditional', NULL, 1, 'GW', 'Kola nut (Cola nitida), a bitter stimulant nut shared at ceremonies and meetings as a sign of hospitality. Culturally essential in Guinea-Bissau''s social customs.', TRUE),
('folhas_de_cha_verde_local_bissau_guinean', 'Folhas de Chá Verde Local', 2, 0.2, 0.3, 0.0, 0.1, 0.0, 200, NULL, 'research', ARRAY['folhas de chá verde local', 'local herbal tea', 'chá de ervas locais'], 'traditional', NULL, 1, 'GW', 'Herbal infusion from locally gathered medicinal plants used as a daily tea. Guinea-Bissau has a rich tradition of herbal teas drawn from forest plants.', TRUE),
('manteiga_de_mancarra_bissau_guinean', 'Manteiga de Mancarra', 615, 24.5, 22.5, 52.0, 6.5, 6.5, 30, NULL, 'research', ARRAY['manteiga de mancarra', 'traditional peanut butter', 'manteiga de amendoim artesanal'], 'traditional', NULL, 1, 'GW', 'Traditional peanut butter made by stone-grinding roasted peanuts, with a coarser, oilier texture than commercial peanut butter. A staple condiment and cooking ingredient.', TRUE),
