('pao_de_amendoim_bissau_guinean', 'Pão de Amendoim', 310, 11.5, 42.5, 12.5, 3.0, 6.5, 70, 70, 'research', ARRAY['pão de amendoim', 'peanut bread', 'pão de mancarra'], 'bread', NULL, 1, 'GW', 'Peanut bread made with ground peanuts incorporated into the bread dough, a uniquely Guinean creation. The peanut enriches the flavor and protein content.', TRUE),
